SELECT id, tenant_id, name, type, host, port, database_name, username, connection_config, status, last_test_time, last_test_result, description, created_by, updated_by, created_at, updated_at, deleted_at FROM data_source WHERE tenant_id = #{tenantId} AND deleted_at IS NULL
AND name LIKE '%' || #{name} || '%'
AND type = #{type}
ORDER BY created_at DESC LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*) FROM data_source WHERE tenant_id = #{tenantId} AND deleted_at IS NULL
AND name LIKE '%' || #{name} || '%'
AND type = #{type}
